using Azure.Storage.Blobs;

var client = new BlobServiceClient(
    new Uri("https://<account>.blob.core.windows.net"),
    new DefaultAzureCredential());

var container = client.GetBlobContainerClient("assets");
await container.CreateIfNotExistsAsync(
    Azure.Storage.Blobs.Models.PublicAccessType.Blob);

var blob = container.GetBlobClient("logo.png");
await blob.UploadAsync("./logo.png", overwrite: true);

Console.WriteLine($"Uploaded to: {blob.Uri}");

// host.json — tune timeout and always-ready for Premium plan
{
  "version": "2.0",
  "functionTimeout": "00:30:00",
  "extensions": {
    "http": {
      "routePrefix": "api"
    }
  }
}

// Program.cs — register expensive clients once at startup, not per-invocation
var host = new HostBuilder()
    .ConfigureFunctionsWorkerDefaults()
    .ConfigureServices(services =>
    {
        // Singleton: initialized once per cold start, reused across warm invocations
        services.AddSingleton(_ =>
            new BlobServiceClient(Environment.GetEnvironmentVariable("AzureWebJobsStorage")));
    })
    .Build();

await host.RunAsync();

// Cloudflare Worker proxying to Azure Container App
export default {
  async fetch(request: Request, env: Env): Promise<Response> {
    const url = new URL(request.url);
    const azureOrigin = "https://my-app.azurecontainerapps.io";

    // Geo-based variant decision at CF edge — no Azure hop needed
    const country = request.cf?.country ?? "US";
    const variant = country === "IN" ? "v2" : "v1";

    url.hostname = new URL(azureOrigin).hostname;
    const proxied = new Request(url.toString(), request);
    proxied.headers.set("X-Edge-Variant", variant);
    proxied.headers.set("X-Forwarded-Country", country);

    return fetch(proxied);
  },
} satisfies ExportedHandler<Env>;

